worked_example.final_code:
import java.util.*;
import java.util.stream.*;

interface Repository<T, ID> {
    Optional<T> findById(ID id);
    List<T> findAll();
    T save(T entity);
    void delete(T entity);
    long count();
    default boolean exists(ID id) { return findById(id).isPresent(); }
    default List<T> saveAll(List<T> entities) {
        return entities.stream().map(this::save).collect(Collectors.toList());
    }
}

interface Mapper<S, T> {
    T mapTo(S source);
    default List<T> mapAllTo(List<S> sources) {
        return sources.stream().map(this::mapTo).collect(Collectors.toList());
    }
}

interface Validator<T> {
    boolean isValid(T item);
    String errorMessage();
}

interface Builder<T> { T build(); }

class Order {
    String id, customerId, item;
    double amount;
    Order(String i, String c, String item, double a) { id=i; customerId=c; this.item=item; amount=a; }
    String getId()         { return id; }
    String getCustomerId() { return customerId; }
    String getItem()       { return item; }
    double getAmount()     { return amount; }
    public String toString() { return id + "|" + item + "|₹" + amount; }
}

class OrderDto {
    String orderId, item; double amount;
    OrderDto(String i, String item, double a) { orderId=i; this.item=item; amount=a; }
    public String toString() { return "Dto[" + orderId + "," + item + ",₹" + amount + "]"; }
}

class OrderRepository implements Repository<Order, String> {
    private Map<String, Order> store = new HashMap<>();
    public Optional<Order> findById(String id) { return Optional.ofNullable(store.get(id)); }
    public Order save(Order o) { store.put(o.getId(), o); return o; }
    public List<Order> findAll()  { return new ArrayList<>(store.values()); }
    public void delete(Order o)   { store.remove(o.getId()); }
    public long count()           { return store.size(); }
}

class OrderMapper implements Mapper<Order, OrderDto> {
    public OrderDto mapTo(Order o) { return new OrderDto(o.getId(), o.getItem(), o.getAmount()); }
}

class PositiveAmountValidator implements Validator<Order> {
    public boolean isValid(Order o) { return o.getAmount() > 0; }
    public String errorMessage()    { return "Amount must be positive"; }
}

class OrderBuilder implements Builder<Order> {
    private String id, cid, item;
    private double amount;
    OrderBuilder id(String i)       { id=i;      return this; }
    OrderBuilder customer(String c) { cid=c;     return this; }
    OrderBuilder item(String i)     { item=i;    return this; }
    OrderBuilder amount(double a)   { amount=a;  return this; }
    public Order build() {
        Objects.requireNonNull(id, "id required");
        Objects.requireNonNull(cid, "customerId required");
        return new Order(id, cid, item, amount);
    }
}

public class EcommerceBackend {
    public static void main(String[] args) {
        OrderRepository   repo      = new OrderRepository();
        OrderMapper       mapper    = new OrderMapper();
        Validator<Order>  validator = new PositiveAmountValidator();

        List<Order> orders = List.of(
            new OrderBuilder().id("ORD-001").customer("C001").item("Mouse").amount(799).build(),
            new OrderBuilder().id("ORD-002").customer("C001").item("Keyboard").amount(1999).build(),
            new OrderBuilder().id("ORD-003").customer("C002").item("Monitor").amount(-100).build()  // invalid
        );

        int saved = 0;
        for (Order o : orders) {
            if (validator.isValid(o)) { repo.save(o); saved++; }
            else System.out.println("Rejected " + o.getId() + ": " + validator.errorMessage());
        }

        System.out.println("Saved: " + saved + " | Count: " + repo.count());
        System.out.println("Exists ORD-001: " + repo.exists("ORD-001"));

        List<OrderDto> dtos = mapper.mapAllTo(repo.findAll());
        System.out.println("DTOs: " + dtos.size());

        repo.findById("ORD-001")
            .map(mapper::mapTo)
            .ifPresent(dto -> System.out.println("Found: " + dto));
    }
}
